// Move fact_candidates rows to fact_concepts for the target concept.
// ON CONFLICT DO NOTHING so facts already linked to the target
// (via a prior candidate resolution or direct fact_concepts link)
// are not duplicated.
func (q *Queries) ReassignFactCandidatesToConcept(ctx context.Context, arg ReassignFactCandidatesToConceptParams) error {
	_, err := q.db.Exec(ctx, reassignFactCandidatesToConcept, arg.NewConceptID, arg.OldCandidateID)
	return err
}

const reassignFactConceptsToConcept = `-- name: ReassignFactConceptsToConcept :exec
INSERT INTO okt_repository.fact_concepts (fact_id, concept_id, first_seen_at, promptset_hash)
SELECT fc.fact_id, $1, fc.first_seen_at, fc.promptset_hash
FROM okt_repository.fact_concepts fc
WHERE fc.concept_id = $2
ON CONFLICT (fact_id, concept_id) DO NOTHING
`

type ReassignFactConceptsToConceptParams struct {
	NewConceptID pgtype.UUID `json:"new_concept_id"`
	OldConceptID pgtype.UUID `json:"old_concept_id"`
}

// Re-link every fact_concepts row pointing at old_concept_id to
// new_concept_id, ignoring (fact_id, new_concept_id) pairs that
// already exist (ON CONFLICT DO NOTHING). Used by the migrate_context
// merge path before deleting the old concept row. Preserves the
// promptset_hash of each link so a merge does not silently drop the
// philosophy tag.
func (q *Queries) ReassignFactConceptsToConcept(ctx context.Context, arg ReassignFactConceptsToConceptParams) error {
	_, err := q.db.Exec(ctx, reassignFactConceptsToConcept, arg.NewConceptID, arg.OldConceptID)
	return err
}

const recordFactConceptSkip = `-- name: RecordFactConceptSkip :one
INSERT INTO okt_repository.fact_concept_skips (fact_id, last_error)
VALUES ($1, $2)
ON CONFLICT (fact_id) DO UPDATE
SET last_error = EXCLUDED.last_error,
    skipped_at = now()
RETURNING fact_id, last_error, skipped_at
`

type RecordFactConceptSkipParams struct {
	FactID    pgtype.UUID `json:"fact_id"`
	LastError string      `json:"last_error"`
}

// Permanently marks a fact as skipped for concept extraction
// (e.g. the LLM returned a transient error and we don't want to
// retry it on every subsequent pass, since there is no periodic
// re-driver). An operator must delete the row to retry. ON
// CONFLICT DO UPDATE so re-skipping the same fact refreshes the
// last_error and skipped_at.
func (q *Queries) RecordFactConceptSkip(ctx context.Context, arg RecordFactConceptSkipParams) (OktRepositoryFactConceptSkip, error) {
	row := q.db.QueryRow(ctx, recordFactConceptSkip, arg.FactID, arg.LastError)
	var i OktRepositoryFactConceptSkip
	err := row.Scan(&i.FactID, &i.LastError, &i.SkippedAt)
	return i, err
}

const relinkFactConcepts = `-- name: RelinkFactConcepts :exec
INSERT INTO okt_repository.fact_concepts (fact_id, concept_id, first_seen_at, promptset_hash)
SELECT $1, fc.concept_id, fc.first_seen_at, fc.promptset_hash
FROM okt_repository.fact_concepts fc
WHERE fc.fact_id = $2
ON CONFLICT (fact_id, concept_id) DO NOTHING
`

type RelinkFactConceptsParams struct {
	WinnerID pgtype.UUID `json:"winner_id"`
	LoserID  pgtype.UUID `json:"loser_id"`
}

// Copy a loser fact's concept links onto the winner before the
// loser is deleted (ON DELETE CASCADE would otherwise drop them).
// ON CONFLICT DO NOTHING preserves the winner's existing links.
// Called by the dedup worker's mergeSources, alongside
// RelinkFactReferences, so a dedup merge preserves all concept
// mappings from both the winner and the loser. Preserves the
// promptset_hash of each link so a dedup merge does not silently
// drop the philosophy tag.
func (q *Queries) RelinkFactConcepts(ctx context.Context, arg RelinkFactConceptsParams) error {
	_, err := q.db.Exec(ctx, relinkFactConcepts, arg.WinnerID, arg.LoserID)
	return err
}

const resetConceptEmbedding = `-- name: ResetConceptEmbedding :exec
UPDATE okt_repository.concepts
SET embedded_at = NULL
WHERE id = $1
`

// Force re-embed a concept after its fact set or context changed
// (the merge path of migrate_context re-links facts onto a target
// concept, so the target's vector is stale until re-embedded). Sets
// embedded_at = NULL so the embed_concepts worker picks it up.
func (q *Queries) ResetConceptEmbedding(ctx context.Context, id pgtype.UUID) error {
	_, err := q.db.Exec(ctx, resetConceptEmbedding, id)
	return err
}

const resetConceptEmbeddingForReembed = `-- name: ResetConceptEmbeddingForReembed :exec
UPDATE okt_repository.concepts
SET embedded_at = NULL,
    embedded_model = NULL
WHERE id = ANY($1::uuid[])
`

// Batch version of ResetConceptEmbedding for the CacheReconciler's
// re-embed path. Clears embedded_at + embedded_model on a set of
// concepts so the embed_concepts worker (which filters
// embedded_at IS NULL) re-embeds them with the local model. The
// Qdrant points for these concepts are deleted separately by the
// caller (now possible because Qdrant uses local concept UUIDs,
// not remote registry UUIDs).
func (q *Queries) ResetConceptEmbeddingForReembed(ctx context.Context, dollar_1 []pgtype.UUID) error {
	_, err := q.db.Exec(ctx, resetConceptEmbeddingForReembed, dollar_1)
	return err
}

const resolveCandidate = `-- name: ResolveCandidate :exec
UPDATE okt_repository.concept_candidates
SET resolved_concept_id = $1,
    resolved_at = now()
WHERE id = $2
`

type ResolveCandidateParams struct {
	ResolvedConceptID pgtype.UUID `json:"resolved_concept_id"`
	ID                pgtype.UUID `json:"id"`
}

// Mark a candidate as resolved: record which concept it maps to
// and when. The candidate row stays as a cache entry for future
// extractions of the same (concept_text, context).
func (q *Queries) ResolveCandidate(ctx context.Context, arg ResolveCandidateParams) error {
	_, err := q.db.Exec(ctx, resolveCandidate, arg.ResolvedConceptID, arg.ID)
	return err
}

const setConceptRefinedAt = `-- name: SetConceptRefinedAt :exec
UPDATE okt_repository.concepts
SET aliases_refined_at = now()
WHERE id = $1
`

// Mark a concept as refined at the current time so refine_concepts
