func (q *Queries) SetConceptRefinedAt(ctx context.Context, id pgtype.UUID) error {
	_, err := q.db.Exec(ctx, setConceptRefinedAt, id)
	return err
}

const updateConceptCanonical = `-- name: UpdateConceptCanonical :exec
UPDATE okt_repository.concepts
SET canonical_name = $1
WHERE id = $2
`

type UpdateConceptCanonicalParams struct {
	CanonicalName string      `json:"canonical_name"`
	ID            pgtype.UUID `json:"id"`
}

// Rename a concept's canonical_name. Used by refine_concepts when
// the AI proposes a different canonical than the extracted text
// (step 3c). The advisory lock held by the worker prevents a
// parallel refinement from racing on the same canonical.
func (q *Queries) UpdateConceptCanonical(ctx context.Context, arg UpdateConceptCanonicalParams) error {
	_, err := q.db.Exec(ctx, updateConceptCanonical, arg.CanonicalName, arg.ID)
	return err
}

const updateConceptContext = `-- name: UpdateConceptContext :exec
UPDATE okt_repository.concepts
SET context = $1
WHERE id = $2
`

type UpdateConceptContextParams struct {
	Context string      `json:"context"`
	ID      pgtype.UUID `json:"id"`
}

// Reassign a single concept's context (the migrate_context path
// where no target (name, new_context) exists, so a plain UPDATE is
// safe). The unique index on (repo, lower(name), lower(context))
// guarantees no conflict at this point because the caller already
// checked GetConceptByNameContext returned no rows.
func (q *Queries) UpdateConceptContext(ctx context.Context, arg UpdateConceptContextParams) error {
	_, err := q.db.Exec(ctx, updateConceptContext, arg.Context, arg.ID)
	return err
}
